parameters.jsCode:
const body = $json;

// ดึงรายการ technicians จาก response
const technicians =
  body.technicians ||
  body.response?.technicians ||
  body.message_response?.technicians ||
  [];

// ข้อมูลที่ผู้ใช้ส่งมา
const source = $('Code_Normalize_Identifier').item.json;
const employeeIdInput = String(source.employeeIdInput ?? '').trim();
const technicianNameInput = String(source.technicianNameInput ?? '').trim();

const normalize = (s) =>
  String(s ?? '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ');

// normalize input
const normalizedInputName = normalize(technicianNameInput);

// กรองเฉพาะคนที่ employee_id ตรง
const employeeMatches = technicians.filter((t) => {
  const empId = String(t.employee_id ?? '').trim();
  return empId === employeeIdInput;
});

// กรองต่อด้วยชื่อ
const exactMatches = employeeMatches.filter((t) => {
  const name1 = normalize(t.name);
  const name2 = normalize(t.display_name);
  return name1 === normalizedInputName || name2 === normalizedInputName;
});

let matchStatus = 'not_found';
let tech = null;

if (exactMatches.length === 1) {
  matchStatus = 'matched';
  const t = exactMatches[0];

  tech = {
    id: t.id ?? t.technician_id ?? '',
    name: t.name ?? t.display_name ?? '',
    email: t.email_id ?? t.email ?? '',
    employee_id: t.employee_id ?? '',
    technician_code: t.technician_code ?? '',
    is_active: t.is_active ?? true
  };
} else if (exactMatches.length > 1) {
  matchStatus = 'ambiguous';
} else {
  matchStatus = 'not_found';
}

return [{
  json: {
    ...source,
    totalTechniciansReturned: technicians.length,
    employeeMatchesCount: employeeMatches.length,
    exactMatchesCount: exactMatches.length,
    matchStatus,
    foundTechnician: matchStatus === 'matched',
    technician: tech
  }
}];

const text = ($('Code_Parse_Line_Event').item.json.text ?? '').trim();

// แยกด้วย comma ตัวแรก
const parts = text.split(',');

// helper
const clean = (s) => (s ?? '').trim();
const normalizeName = (s) =>
  clean(s)
    .toLowerCase()
    .replace(/\s+/g, ' '); // ลดช่องว่างหลายตัวให้เหลือ 1

let employeeIdInput = '';
let technicianNameInput = '';
let inputValid = false;
let inputError = '';

if (parts.length < 2) {
  inputError = 'กรุณาส่งข้อมูลในรูปแบบ employee id,ชื่อ';
} else {
  employeeIdInput = clean(parts[0]);

  // กรณีชื่อมี comma เกินมา ให้รวมกลับ
  technicianNameInput = clean(parts.slice(1).join(','));

  if (!employeeIdInput) {
    inputError = 'ไม่พบ employee id';
  } else if (!/^\d+$/.test(employeeIdInput)) {
    inputError = 'employee id ต้องเป็นตัวเลขเท่านั้น';
  } else if (!technicianNameInput) {
    inputError = 'ไม่พบชื่อ technician';
  } else {
    inputValid = true;
  }
}

return [{
  json: {
    ...$('Code_Parse_Line_Event').item.json,
    originalInput: text,
    employeeIdInput,
    technicianNameInput,
    normalizedTechnicianNameInput: normalizeName(technicianNameInput),
    inputValid,
    inputError
  }
}];

